// // This module compares two 4-bit values and outputs whether they are not equal, with in_a being less than or equal to in_b, and in_a being greater than or equal to in_b.
module top_module(
    input [3:0] in_a,
    input [3:0] in_b,
    output eq,
    output gt,
    output lt
);assign eq = (in_a == in_b);
    assign gt = (in_a > in_b);
    assign lt = (in_a < in_b);

endmodule
